import java.io.*;
import javax.servlet.*;
import javax.servlet.http.*;

public class SecureServlet extends HttpServlet {

    @Override
    protected void doPost(HttpServletRequest request, HttpServletResponse response) throws ServletException, IOException {
        String userInput = request.getParameter("input");

        PrintWriter out = response.getWriter();
        out.println("<html>");
        out.println("<body>");
        out.println("User input: " + encodeHtml(userInput)); // Encode user input before printing
        out.println("</body>");
        out.println("</html>");
    }

    private String encodeHtml(String input) {
        return org.owasp.encoder.Encode.forHtml(input); // Use OWASP ESAPI library for HTML encoding
    }
}

### Explanation:
취약유형: Cross-Site Scripting (XSS)
